Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,30 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+
+  let i = 0
+  while (i < argv.length && argv[i].startsWith('-')) {
+    const arg = argv[i]
+    const key = arg.slice(2)
+    const hasEquals = key.includes('=')
+
+    if (hasEquals) {
+      const eqIndex = key.indexOf('=')
+      const k = key.slice(0, eqIndex)
+      const val = key.slice(eqIndex + 1)
+      result[k] = val
+    } else if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
+      result[key] = argv[i + 1]
+      i += 1
+    } else {
+      result[key] = true
+    }
+    i += 1
   }
+
+  while (i < argv.length) {
+    result._.push(argv[i])
+    i += 1
+  }
+
   return result
 }

